mapper.select:
SELECT id, name, parent_id, manager_id, contact, location, sort_order
FROM gw_departments
WHERE id = #{id}

mapper.update:
UPDATE gw_positions
SET name          = #{name},
    level         = #{level},
    approval_rank = #{approvalRank}
WHERE id = #{id}

UPDATE gw_boards
SET name          = #{name},
    department_id = #{departmentId},
    description   = #{description}
WHERE id = #{id}

UPDATE gw_meeting_rooms
SET name        = #{name},
    capacity    = #{capacity},
    location    = #{location},
    description = #{description}
WHERE id = #{id}
